const envelope = $json || {};
const data = envelope.data || {};
const customer = data.customer || {};
const payment = data.payment || {};
const items = Array.isArray(data.items) ? data.items : [];

const previewItems = items.slice(0, 5).map((item, index) => {
  const title = item?.title || 'Livre';
  const qty = Number(item?.qty || 1);
  const price = Number(item?.price || 0).toLocaleString('fr-FR');
  return `${index + 1}. ${title} x${qty} (${price} GNF)`;
});

return [{
  json: {
    orderId: data.orderId || 'N/A',
    status: data.status || 'pending',
    total: Number(data.total || 0),
    discount: Number(data.discount || 0),
    promoCode: data.promoCode || '',
    customerName: customer.name || 'Client',
    phone: customer.phone || 'N/A',
    reference: payment.referencePaiement || payment.txId || 'N/A',
    itemCount: items.length,
    previewItems
  }
}];

const statusMap = {
  pending: '[WAIT] En attente',
  approved: '[OK] Approuvee',
  rejected: '[NO] Rejetee'
};

const statusLabel = statusMap[$json.status] || $json.status;
const total = Number($json.total || 0).toLocaleString('fr-FR');
const discount = Number($json.discount || 0).toLocaleString('fr-FR');

const lines = [
  'Nouvelle commande Librairie YO',
  `Commande: #${$json.orderId}`,
  `Statut: ${statusLabel}`,
  `Client: ${$json.customerName}`,
  `Telephone: +${$json.phone}`,
  `Reference paiement: ${$json.reference}`,
  `Total: ${total} GNF`,
  `Reduction: ${discount} GNF`,
  $json.promoCode ? `Code promo: ${$json.promoCode}` : null,
  `Articles: ${$json.itemCount}`,
  ...($json.previewItems || [])
].filter(Boolean);

return [{ json: { text: lines.join('\n') } }];
